function i(e,t="CDF"){let r;typeof e=="string"?r=Number(e.replace(/\s/g,"").replace(",",".")):e==null?r=0:r=e,Number.isFinite(r)||(r=0);try{return new Intl.NumberFormat("fr-FR",{style:"currency",currency:t||"CDF",minimumFractionDigits:2,maximumFractionDigits:2,useGrouping:!0}).format(r)}catch{return`${(Number.isFinite(r)?r:0).toFixed(2).replace(".",",")} ${t||"CDF"}`}}function a(e,t,r=!1){if(!e)return r?new Date().toLocaleDateString("fr-FR",{year:"numeric",month:"long",day:"numeric"}):"-";const n=typeof e=="string"?new Date(e):e;return isNaN(n.getTime())?r?new Date().toLocaleDateString("fr-FR",{year:"numeric",month:"long",day:"numeric"}):"-":n.toLocaleDateString("fr-FR",{year:"numeric",month:"long",day:"numeric"})}function o(e,t){return a(e,t,!0)}function u(e,t="CDF"){return i(e,t)}export{o as a,a as b,u as c,i as f};
